#include <stdio.h>
#include <string.h>

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        char s[105]; scanf("%100s",s);
        int n=strlen(s);
        int snakes=0,mongooses=0;
        for(int i=0;i<n;++i){ if(s[i]=='s') ++snakes; else ++mongooses; }
        for(int i=0;i<n;++i){
            if(s[i]=='m'){
                if(i>0 && s[i-1]=='s'){ --snakes; s[i-1]='x'; }
                else if(i+1<n && s[i+1]=='s'){ --snakes; s[i+1]='x'; }
            }
        }
        if(snakes>mongooses) printf("snakes\n");
        else if(snakes<mongooses) printf("mongooses\n");
        else printf("tie\n");
    }
    return 0;
}

