import sys
def solve():
    data=sys.stdin.read().strip().splitlines()
    if not data: return
    T=int(data[0])
    out=[]
    for i in range(1,T+1):
        s=data[i].strip()
        arr=list(s)
        snakes=s.count('s')
        mongooses=s.count('m')
        for idx,ch in enumerate(arr):
            if ch=='m':
                if idx>0 and arr[idx-1]=='s':
                    snakes-=1
                    arr[idx-1]='x'
                elif idx+1<len(arr) and arr[idx+1]=='s':
                    snakes-=1
                    arr[idx+1]='x'
        if snakes>mongooses:
            out.append('snakes')
        elif snakes<mongooses:
            out.append('mongooses')
        else:
            out.append('tie')
    sys.stdout.write('\n'.join(out))
if __name__=='__main__':
    solve()

